// --- AUTH ---
export const loginWithEmail = (email: string, password: string) => supabase.auth.signInWithPassword({ email, password });

/**
 * Inicia el flujo de OAuth con Google.
 * Supabase redirigirá al usuario a la página de selección de cuenta de Google.
 */
export const loginWithGoogle = async () => {
    return await supabase.auth.signInWithOAuth({ 
        provider: 'google', 
        options: { 
            redirectTo: window.location.origin,
            queryParams: {
                access_type: 'offline',
                prompt: 'select_account'
            }
        } 
    });
};

export const registerWithEmail = (email: string, password: string, name: string) => supabase.auth.signUp({ email, password, options: { data: { full_name: name } } });
export const logoutUser = () => supabase.auth.signOut();
export const resetPassword = (email: string) => supabase.auth.resetPasswordForEmail(email, {
    redirectTo: window.location.origin,
});

// --- DATABASE ---
export const getShopForUser = async (userId: string): Promise<BarberShop | null> => {
    const { data, error } = await supabase.from('shops').select('*').eq('id', userId).maybeSingle();
    if (error || !data) return null;
    return mapShopFromDb(data);
};

export const createDefaultShopForUser = async (userId: string, userName: string) => {
    const defaultShop = {
        id: userId,
        owner_id: userId,
        name: `${userName || 'Mi'} Barbería`,
        ai_name: 'Asistente Virtual',
        welcome_message: '¡Hola! Bienvenido.',
        ai_persona: 'Profesional amable.',
        description: 'Nueva barbería registrada.',
        address: 'Pendiente',
        phone: '000-000',
        hours: { 'Lunes-Viernes': '09:00 - 18:00' },
        galery: [],
        services: [{ name: 'Corte', price: '$20' }],
        barbers: [{ name: userName || 'Dueño', specialty: 'General', imageUrl: '' }],
        plan: 'Freemium'
    };
    const { data, error } = await supabase.from('shops').upsert([defaultShop]).select();
    return { data: data?.[0] ? mapShopFromDb(data[0]) : null, error };
};

export const updateShopInSupabase = (shopId: string, updates: Partial<BarberShop>) => {
    if (updates.gallery) {
        updates.gallery = updates.gallery.filter(url => 
            typeof url === 'string' && url.startsWith('http')
        );
    }
    const cleanData = mapShopToDb(updates);
    return supabase.from('shops').update(cleanData).eq('id', shopId);
};

export const saveBookingToSupabase = (booking: Omit<Booking, 'id'>) => supabase.from('bookings').insert([{
    shop_name: booking.shopName,
    service: booking.service,
    date: booking.date,
    time: booking.time,
    user_id: booking.userId
}]);

export const subscribeToBookings = (shopName: string, callback: (bookings: Booking[]) => void) => {
    const fetchBookings = async () => {
        const { data } = await supabase.from('bookings').select('*').eq('shop_name', shopName).order('date', { ascending: true });
        if (data) callback(data.map(b => ({
            id: b.id,
            shopName: b.shop_name,
            service: b.service,
            date: b.date,
            time: b.time,
            userId: b.user_id,
            createdAt: b.created_at
        })));
    };
    fetchBookings();
    const channel = supabase.channel(`bookings_${shopName}`).on('postgres_changes', { event: '*', schema: 'public', table: 'bookings', filter: `shop_name=eq.${shopName}` }, fetchBookings).subscribe();
    return () => { supabase.removeChannel(channel); };
};

