                                            type="button" 
                                            onClick={() => {
                                                setIsResettingPassword(true);
                                                setError(null);
                                                setSuccessMsg(null);
                                            }}
                                            className="text-[9px] font-black text-red-600 uppercase tracking-widest hover:underline"
                                        >
