                                </div>
                                <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl text-slate-950 font-bold focus:border-red-600 outline-none transition-all placeholder-slate-300" placeholder="••••••••" />
