    phone: data.phone || '',
    hours: data.hours || {},
    gallery: data.galery || [], 
    services: data.services || [],
    barbers: data.barbers || [],
    plan: data.plan || 'Freemium',
    billingHistory: [],
    paymentMethod: { type: 'Visa', last4: '0000', expiry: '00/00' }
});

const mapShopToDb = (shop: Partial<BarberShop>) => {
    const out: any = { ...shop };
    if (shop.ownerId) { out.owner_id = shop.ownerId; delete out.ownerId; }
    if (shop.aiName) { out.ai_name = shop.aiName; delete out.aiName; }
    if (shop.welcomeMessage) { out.welcome_message = shop.welcomeMessage; delete out.welcomeMessage; }
    if (shop.aiPersona) { out.ai_persona = shop.aiPersona; delete out.aiPersona; }
    if (shop.gallery) { out.galery = shop.gallery; delete out.gallery; }
    delete out.billingHistory;
    delete out.paymentMethod;
    return out;
};

