    date: booking.date,
    time: booking.time,
    user_id: booking.userId
}]);

export const subscribeToBookings = (shopName: string, callback: (bookings: Booking[]) => void) => {
    const fetchBookings = async () => {
        const { data } = await supabase.from('bookings').select('*').eq('shop_name', shopName).order('date', { ascending: true });
        if (data) callback(data.map(b => ({
            id: b.id,
            shopName: b.shop_name,
            service: b.service,
            date: b.date,
            time: b.time,
            userId: b.user_id,
            createdAt: b.created_at
        })));
    };
    fetchBookings();
    const channel = supabase.channel(`bookings_${shopName}`).on('postgres_changes', { event: '*', schema: 'public', table: 'bookings', filter: `shop_name=eq.${shopName}` }, fetchBookings).subscribe();
    return () => { supabase.removeChannel(channel); };
};

